const opps = $input.first().json;
const clients = $('Buscar Novos Clientes').first().json;
const closed = Array.isArray(opps) ? opps.filter(o => o.stage === 'venda_fechada') : [];
const revenue = closed.reduce((s, o) => s + (o.estimated_value || 0), 0);
return [{ json: {
  total_opps: Array.isArray(opps) ? opps.length : 0,
  closed_deals: closed.length,
  revenue,
  new_clients: Array.isArray(clients) ? clients.length : 0
}}];

